// ============================================================================
// BUSINESS IMAGE (with placeholder + fallback)
// ============================================================================
// ============================================================================
// BUSINESS VIDEO — Renders an inline HTML5 video with poster + play overlay.
// For businesses with reels/clips (Instagram, TikTok, behind-the-scenes).
// Falls back to a static poster image if no videoUrl is supplied — useful
// for the "video coming soon" state during onboarding.
// ============================================================================
function BusinessVideo({ video, accent, aspect = '4/5', style = {}, label }) {
  const [playing, setPlaying] = useState(false);
  const ref = useRef(null);

  const handlePlay = () => {
    if (!video?.videoUrl) return; // No real video to play — poster only
    if (ref.current) {
      ref.current.play();
      setPlaying(true);
    }
  };

  if (!video?.posterUrl && !video?.videoUrl) {
    return (
      <div style={{
        aspectRatio: aspect,
        background: `linear-gradient(135deg, ${accent}10 0%, ${accent}03 100%)`,
        border: `1px solid ${accent}25`,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        ...style
      }}>
        <div style={{
          fontFamily: 'Fraunces, Georgia, serif', fontStyle: 'italic',
          color: accent, opacity: 0.55
        }}>
          Video coming soon
        </div>
      </div>
    );
  }

  return (
    <div style={{
      position: 'relative', aspectRatio: aspect, overflow: 'hidden',
      background: '#0c0c0c', cursor: video?.videoUrl ? 'pointer' : 'default',
      ...style
    }} onClick={handlePlay}>
      {video.videoUrl && playing ? (
        <video ref={ref} src={video.videoUrl} controls autoPlay
          style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
      ) : (
        <>
          <img src={video.posterUrl} alt={video.alt || ''} loading="lazy"
            style={{
              width: '100%', height: '100%', objectFit: 'cover',
              filter: 'contrast(1.05) saturate(0.95)'
            }} />
          {/* Play overlay */}
          <div style={{
            position: 'absolute', inset: 0,
            background: 'linear-gradient(180deg, transparent 0%, rgba(8,8,8,0.5) 100%)',
            display: 'flex', alignItems: 'center', justifyContent: 'center'
          }}>
            <div style={{
              width: 64, height: 64, borderRadius: '50%',
              background: 'rgba(8,8,8,0.6)', backdropFilter: 'blur(10px)',
              border: `2px solid ${accent}`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              transition: 'all 200ms ease'
            }}>
              <svg width="20" height="22" viewBox="0 0 24 24" fill={accent} style={{ marginLeft: 3 }}>
                <path d="M8 5v14l11-7z"/>
              </svg>
            </div>
          </div>
          {label && (
            <div style={{
              position: 'absolute', bottom: 16, left: 16, right: 16,
              padding: '6px 12px',
              background: 'rgba(8,8,8,0.78)', backdropFilter: 'blur(6px)',
              border: '1px solid rgba(255,255,255,0.1)', borderRadius: 6,
              fontSize: 11, fontFamily: 'Geist Mono, monospace',
              letterSpacing: '0.14em', textTransform: 'uppercase',
              color: accent, fontWeight: 500, display: 'inline-block',
              width: 'fit-content'
            }}>
              {label}
            </div>
          )}
        </>
      )}
    </div>
  );
}


function BusinessImage({ image, fallbackLabel, accent, aspect = '4/3', style = {}, showPlaceholderTag = true }) {
  const [hover, setHover] = useState(false);
  if (image?.url) {
    return (
      <div style={{
        position: 'relative', aspectRatio: aspect, overflow: 'hidden',
        background: '#0c0c0c', ...style
      }}
        onMouseEnter={() => setHover(true)}
        onMouseLeave={() => setHover(false)}
      >
        <img src={image.url} alt={image.alt || ''} loading="lazy" style={{
          width: '100%', height: '100%', objectFit: 'cover',
          filter: 'contrast(1.05) saturate(0.95)',
          transform: hover ? 'scale(1.03)' : 'scale(1)',
          transition: 'transform 600ms cubic-bezier(0.16, 1, 0.3, 1)'
        }} />
        {image.placeholder && showPlaceholderTag && (
          <div style={{
            position: 'absolute', top: 12, left: 12,
            padding: '3px 8px', background: 'rgba(8,8,8,0.78)',
            backdropFilter: 'blur(6px)', borderRadius: 6,
            border: '1px solid rgba(255,255,255,0.1)',
            fontSize: 9, fontFamily: 'Geist Mono, monospace',
            letterSpacing: '0.14em', textTransform: 'uppercase', opacity: 0.75
          }}>
            Placeholder
          </div>
        )}
        {image.caption && (
          <div style={{
            position: 'absolute', bottom: 0, left: 0, right: 0,
            padding: '24px 16px 14px',
            background: 'linear-gradient(180deg, transparent 0%, rgba(8,8,8,0.92) 100%)',
            fontSize: 13, fontFamily: 'Geist, system-ui',
            color: 'rgba(255,255,255,0.95)',
            opacity: hover ? 1 : 0,
            transform: hover ? 'translateY(0)' : 'translateY(8px)',
            transition: 'all 400ms cubic-bezier(0.16, 1, 0.3, 1)',
            pointerEvents: 'none'
          }}>
            {image.caption}
          </div>
        )}
      </div>
    );
  }
  return (
    <div style={{
      aspectRatio: aspect,
      background: `linear-gradient(135deg, ${accent}10 0%, ${accent}03 100%)`,
      border: `1px solid ${accent}25`,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      ...style
    }}>
      <div style={{
        fontFamily: 'Fraunces, Georgia, serif', fontStyle: 'italic',
        fontWeight: 300, fontSize: 'clamp(18px, 2vw, 28px)',
        color: accent, opacity: 0.55, textAlign: 'center', padding: 24
      }}>
        {fallbackLabel}
      </div>
    </div>
  );
}

